import{_ as a,c as e,o as t,a5 as o}from"./chunks/framework.DwbewbAn.js";const u=JSON.parse('{"title":"MQ总结","description":"","frontmatter":{},"headers":[],"relativePath":"doc/消息队列/消息队列/MQ总结.md","filePath":"packages/doc/src/消息队列/消息队列/MQ总结.md","lastUpdated":1707061484000}'),r={name:"doc/消息队列/消息队列/MQ总结.md"},p=o('<h1 id="mq总结" tabindex="-1">MQ总结 <a class="header-anchor" href="#mq总结" aria-label="Permalink to &quot;MQ总结&quot;">​</a></h1><h2 id="_1-生产者发送消息" tabindex="-1">1.生产者发送消息 <a class="header-anchor" href="#_1-生产者发送消息" aria-label="Permalink to &quot;1.生产者发送消息&quot;">​</a></h2><p>1.确认机制：保证消息被接收了</p><p>2.重试机制：网络不好需要支持重试，可能导致重复发送</p><p>3.事务：本地事务+发送消息 要么都成功，要么都失败</p><p>4.提供一个touch方法可以延长发送消息时间</p><p>5.消息有序发送</p><h2 id="_2-消费者接收消息" tabindex="-1">2.消费者接收消息 <a class="header-anchor" href="#_2-消费者接收消息" aria-label="Permalink to &quot;2.消费者接收消息&quot;">​</a></h2><p>1.commit或者delete机制：消费完毕后告诉MQ消费完毕，要么commit offset，要么删除消息</p><p>2.commit失败会造成重复消费：</p><p>3.消费时间太长，又被其他的消费者取到了</p><p>4.提供一个touch方法可以延长消费时间</p><p>5.rebalance问题</p><h2 id="_3-队列问题" tabindex="-1">3.队列问题 <a class="header-anchor" href="#_3-队列问题" aria-label="Permalink to &quot;3.队列问题&quot;">​</a></h2><h4 id="_1-延时队列" tabindex="-1">1.延时队列 <a class="header-anchor" href="#_1-延时队列" aria-label="Permalink to &quot;1.延时队列&quot;">​</a></h4><p>1.rabbitmq的延时队列默认情况下，排队到了头部的时候才开始计算延时时间，排队过程中不计算</p><p>会导致逻辑不正确</p><p>2.rabbitmq插件版本的延时队列，发送了以后就开始计时了，过期的时候配置了死信队列就进入到死信队列，没配置就直接被删除</p><p>3.kafka不支持延时队列</p><p>4.rocketmq支持延时队列</p><h4 id="_2-死信队列" tabindex="-1">2.死信队列 <a class="header-anchor" href="#_2-死信队列" aria-label="Permalink to &quot;2.死信队列&quot;">​</a></h4><h2 id="_4-消息问题" tabindex="-1">4.消息问题 <a class="header-anchor" href="#_4-消息问题" aria-label="Permalink to &quot;4.消息问题&quot;">​</a></h2><p>1.offset位移点模式</p><p>2.delete模式</p><p>3.顺序消费</p><h2 id="_5-架构方面" tabindex="-1">5.架构方面 <a class="header-anchor" href="#_5-架构方面" aria-label="Permalink to &quot;5.架构方面&quot;">​</a></h2><p>1.topic partition 多副本机制</p><p>2.topic 多queue副本机制</p><p>3.集群，镜像队列机制</p><p>4.副本优先选举</p><p>5.分区分配策略</p><p>6.副本分配策略</p><h2 id="_6-零拷贝" tabindex="-1">6.零拷贝 <a class="header-anchor" href="#_6-零拷贝" aria-label="Permalink to &quot;6.零拷贝&quot;">​</a></h2><p>1.mmap+write</p><p>2.sendfile</p>',35),i=[p];function h(c,l,d,n,s,_){return t(),e("div",null,i)}const q=a(r,[["render",h]]);export{u as __pageData,q as default};
